inline bool VerifyMessagePayload(::flatbuffers::Verifier &verifier, const void *obj, MessagePayload type) {
  switch (type) {
    case MessagePayload_NONE: {
      return true;
    }
    case MessagePayload_InitialData: {
      auto ptr = reinterpret_cast<const MegaFlowz::InitialData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_BarUpdate: {
      auto ptr = reinterpret_cast<const MegaFlowz::BarUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_PriceUpdate: {
      auto ptr = reinterpret_cast<const MegaFlowz::PriceUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_WatchlistUpdate: {
      auto ptr = reinterpret_cast<const MegaFlowz::WatchlistUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_PositionsUpdate: {
      auto ptr = reinterpret_cast<const MegaFlowz::PositionsUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_ConnectionStatus: {
      auto ptr = reinterpret_cast<const MegaFlowz::ConnectionStatus *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_TradeExecuted: {
      auto ptr = reinterpret_cast<const MegaFlowz::TradeExecuted *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_PositionClosed: {
      auto ptr = reinterpret_cast<const MegaFlowz::PositionClosed *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_PositionModified: {
      auto ptr = reinterpret_cast<const MegaFlowz::PositionModified *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_ErrorMsg: {
      auto ptr = reinterpret_cast<const MegaFlowz::ErrorMsg *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_AutoTradingStatus: {
      auto ptr = reinterpret_cast<const MegaFlowz::AutoTradingStatus *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_CacheCleared: {
      auto ptr = reinterpret_cast<const MegaFlowz::CacheCleared *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyMessagePayloadVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<uint8_t> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyMessagePayload(
        verifier,  values->Get(i), types->GetEnum<MessagePayload>(i))) {
      return false;
    }
  }
  return true;
}

